window.SAMM = {"answerScale":{"pt":["Não","Sim, para alguns","Sim, pelo menos a metade","Sim, a maioria ou todos"],"en":["No","Yes, for some","Yes, at least half","Yes, most or all"],"weights":[0,0.25,0.5,1]},"functions":[{"name":"Governance","pt":"Governança","code":"G","practices":[{"name":"Strategy and Metrics","pt":"Estratégia e Métricas","code":"SM","A":{"en":"Create and Promote","pt":"Criar e Promover"},"B":{"en":"Measure and Improve","pt":"Medir e Melhorar"},"questions":[{"stream":"A","level":1,"en":"Do you understand the enterprise-wide risk appetite for your applications?","pt":"Vocês compreendem o apetite de risco corporativo para suas aplicações?","gen":["You capture the risk appetite of your organization's executive leadership","The organization's leadership vet and approve the set of risks","You identify the main business and technical threats to your assets and data","You document risks and store them in an accessible location"],"gpt":["Vocês capturam o apetite de risco da liderança executiva da organização","A liderança avalia e aprova o conjunto de riscos","Vocês identificam as principais ameaças de negócio e técnicas aos seus ativos e dados","Vocês documentam os riscos e os armazenam em local acessível"]},{"stream":"B","level":1,"en":"Do you use a set of metrics to measure the effectiveness and efficiency of the application security program across applications?","pt":"Vocês usam um conjunto de métricas para medir a eficácia e eficiência do programa de segurança de aplicações entre as aplicações?","gen":["You document each metric, including a description of the sources, measurement coverage, and guidance on how to use it to explain application security trends","Metrics include measures of efforts, results, and the environment measurement categories","Most of the metrics are frequently measured, easy or inexpensive to gather, and expressed as a cardinal number or a percentage","Application security and development teams publish metrics"],"gpt":["Cada métrica é documentada, incluindo fontes, cobertura da medição e orientação de uso para explicar tendências de AppSec","As métricas incluem categorias de esforço, resultados e ambiente","A maioria é medida com frequência, fácil/barata de coletar e expressa como número ou percentual","As equipes de AppSec e desenvolvimento publicam as métricas"]},{"stream":"A","level":2,"en":"Do you have a strategic plan for application security and use it to make decisions?","pt":"Vocês têm um plano estratégico de segurança de aplicações e o utilizam para tomar decisões?","gen":["The plan reflects the organization's business priorities and risk appetite","The plan includes measurable milestones and a budget","The plan is consistent with the organization's business drivers and risks","The plan lays out a roadmap for strategic and tactical initiatives"],"gpt":["O plano reflete as prioridades de negócio e o apetite de risco da organização","O plano inclui marcos mensuráveis e um orçamento","O plano é consistente com os direcionadores e riscos de negócio","O plano traça um roadmap para iniciativas estratégicas e táticas"]},{"stream":"B","level":2,"en":"Did you define Key Performance Indicators (KPI) from available application security metrics?","pt":"Vocês definiram Indicadores-Chave de Desempenho (KPIs) a partir das métricas de segurança de aplicações disponíveis?","gen":["You defined KPIs after gathering enough information to establish realistic objectives","You developed KPIs with the buy-in from the leadership and teams responsible for application security","KPIs are available to the application teams and include acceptability thresholds and guidance in case teams need to take action","Success of the application security program is clearly visible based on defined KPIs"],"gpt":["Vocês definiram KPIs após reunir informação suficiente para estabelecer objetivos realistas","Os KPIs foram desenvolvidos com adesão da liderança e das equipes responsáveis por AppSec","Os KPIs estão disponíveis às equipes e incluem limites de aceitação e orientação para ação","O sucesso do programa de AppSec é claramente visível pelos KPIs definidos"]},{"stream":"A","level":3,"en":"Do you regularly review and update the Strategic Plan for Application Security?","pt":"Vocês revisam e atualizam regularmente o Plano Estratégico de Segurança de Aplicações?","gen":["You review and update the plan in response to significant changes in the business environment, the organization, or its risk appetite","Plan update steps include reviewing the plan with all the stakeholders and updating the business drivers and strategies","You adjust the plan and roadmap based on lessons learned from completed roadmap activities","You publish progress information on roadmap activities, making sure they are available to all stakeholders"],"gpt":["Vocês revisam e atualizam o plano diante de mudanças significativas no ambiente de negócio, na organização ou no apetite de risco","A atualização inclui rever o plano com os stakeholders e atualizar direcionadores e estratégias","Vocês ajustam plano e roadmap com base nas lições aprendidas das atividades concluídas","Vocês publicam o progresso das atividades do roadmap a todos os stakeholders"]},{"stream":"B","level":3,"en":"Do you update the Application Security strategy and roadmap based on application security metrics and KPIs?","pt":"Vocês atualizam a estratégia e o roadmap de Segurança de Aplicações com base em métricas e KPIs?","gen":["You review KPIs at least yearly for their efficiency and effectiveness","KPIs and application security metrics trigger most of the changes to the application security strategy"],"gpt":["Vocês revisam os KPIs ao menos anualmente quanto à eficiência e eficácia","KPIs e métricas de AppSec disparam a maioria das mudanças na estratégia de segurança"]}]},{"name":"Policy and Compliance","pt":"Política e Conformidade","code":"PC","A":{"en":"Policy and Standards","pt":"Políticas e Padrões"},"B":{"en":"Compliance Management","pt":"Gestão de Conformidade"},"questions":[{"stream":"A","level":1,"en":"Do you have and apply a common set of policies and standards throughout your organization?","pt":"Vocês têm e aplicam um conjunto comum de políticas e padrões em toda a organização?","gen":["You have adapted existing standards appropriate for the organization&#8217;s industry to account for domain-specific considerations","Your standards are aligned with your policies and incorporate technology-specific implementation guidance"],"gpt":["Vocês adaptaram padrões existentes apropriados ao setor da organização, considerando particularidades do domínio","Seus padrões estão alinhados às políticas e incorporam orientação de implementação específica por tecnologia"]},{"stream":"B","level":1,"en":"Do you have a complete picture of your external compliance obligations?","pt":"Vocês têm um panorama completo das suas obrigações externas de conformidade?","gen":["You have identified all sources of external compliance obligations","You have captured and reconciled compliance obligations from all sources"],"gpt":["Vocês identificaram todas as fontes de obrigações externas de conformidade","Vocês capturaram e reconciliaram as obrigações de conformidade de todas as fontes"]},{"stream":"A","level":2,"en":"Do you publish the organization's policies as test scripts or run-books for easy interpretation by development teams?","pt":"Vocês publicam as políticas da organização como scripts de teste ou run-books para fácil interpretação pelas equipes de desenvolvimento?","gen":["You create verification checklists and test scripts where applicable, aligned with the policy's requirements and the implementation guidance in the associated standards","You create versions adapted to each development methodology and technology the organization uses"],"gpt":["Vocês criam checklists de verificação e scripts de teste quando aplicável, alinhados aos requisitos das políticas e à orientação dos padrões","Vocês criam versões adaptadas a cada metodologia de desenvolvimento e tecnologia usada"]},{"stream":"B","level":2,"en":"Do you have a standard set of security requirements and verification procedures addressing the organization's external compliance obligations?","pt":"Vocês têm um conjunto padrão de requisitos de segurança e procedimentos de verificação que atendem às obrigações externas de conformidade?","gen":["You map each external compliance obligation to a well-defined set of application requirements","You define verification procedures, including automated tests, to verify compliance with compliance-related requirements"],"gpt":["Vocês mapeiam cada obrigação externa de conformidade a um conjunto bem definido de requisitos da aplicação","Vocês definem procedimentos de verificação, incluindo testes automatizados, para conferir a conformidade"]},{"stream":"A","level":3,"en":"Do you regularly report on policy and standard compliance, and use that information to guide compliance improvement efforts?","pt":"Vocês reportam regularmente a conformidade com políticas e padrões, e usam essa informação para guiar melhorias de conformidade?","gen":["You have procedures (automated, if possible) to regularly generate compliance reports","You deliver compliance reports to all relevant stakeholders","Stakeholders use the reported compliance status information to identify areas for improvement"],"gpt":["Há procedimentos (automatizados, se possível) para gerar relatórios de conformidade regularmente","Vocês entregam os relatórios a todos os stakeholders relevantes","Os stakeholders usam o status de conformidade para identificar áreas de melhoria"]},{"stream":"B","level":3,"en":"Do you regularly report on adherence to external compliance obligations and use that information to guide efforts to close compliance gaps?","pt":"Vocês reportam regularmente a aderência às obrigações externas de conformidade e usam essa informação para fechar lacunas de conformidade?","gen":["You have established, well-defined compliance metrics","You measure and report on applications' compliance metrics regularly","Stakeholders use the reported compliance status information to identify compliance gaps and prioritize gap remediation efforts"],"gpt":["Há métricas de conformidade bem definidas e estabelecidas","Vocês medem e reportam regularmente as métricas de conformidade das aplicações","Os stakeholders usam o status para identificar lacunas e priorizar sua correção"]}]},{"name":"Education and Guidance","pt":"Educação e Orientação","code":"EG","A":{"en":"Training and Awareness","pt":"Treinamento e Conscientização"},"B":{"en":"Organization and Culture","pt":"Organização e Cultura"},"questions":[{"stream":"A","level":1,"en":"Do you require employees involved with application development to take SDLC training?","pt":"Vocês exigem que funcionários envolvidos no desenvolvimento de aplicações façam treinamento de SDLC?","gen":["Training is repeatable, consistent, and available to anyone involved with software development lifecycle","Training includes relevant content from the latest OWASP Top 10 and includes concepts such as Least Privilege, Defense-in-Depth, Fail Secure (Safe), Complete Mediation, Session Management, Open Design, and Psychological Acceptability","Training requires a sign-off or an acknowledgement from attendees","You have reviewed the training content within the last 12 months, and have completed any required updates"],"gpt":["O treinamento é repetível, consistente e disponível a todos os envolvidos no ciclo de desenvolvimento","Inclui conteúdo atual do OWASP Top 10 e conceitos como menor privilégio, defesa em profundidade, fail-secure, mediação completa, gestão de sessão, open design e aceitabilidade psicológica","Exige confirmação/assinatura de participação","O conteúdo foi revisado nos últimos 12 meses, com as atualizações necessárias feitas"]},{"stream":"B","level":1,"en":"Have you identified a Security Champion for each development team?","pt":"Vocês identificaram um Security Champion para cada equipe de desenvolvimento?","gen":["Security Champions receive appropriate training","Application Security and Development teams receive periodic briefings from Security Champions on the overall status of security initiatives and fixes","The Security Champion reviews the results of external testing before adding to the application backlog"],"gpt":["Os Security Champions recebem treinamento adequado","As equipes de AppSec e desenvolvimento recebem briefings periódicos dos Champions sobre o status das iniciativas e correções de segurança","O Security Champion revisa os resultados de testes externos antes de adicioná-los ao backlog"]},{"stream":"A","level":2,"en":"Is training customized for individual roles such as developers, testers, or security champions?","pt":"O treinamento é personalizado para papéis específicos como desenvolvedores, testers ou security champions?","gen":["Training includes all topics from maturity level 1, and adds more specific tools, techniques, and demonstrations","Training is mandatory for all employees and contractors","Training includes input from in-house SMEs and trainees","Training includes demonstrations of tools and techniques developed in-house"],"gpt":["O treinamento inclui todos os tópicos do nível 1 e adiciona ferramentas, técnicas e demonstrações mais específicas","É obrigatório para todos os funcionários e terceiros","Inclui contribuições de especialistas internos e dos participantes","Inclui demonstrações de ferramentas e técnicas desenvolvidas internamente"]},{"stream":"B","level":2,"en":"Does the organization have a Secure Software Center of Excellence (SSCE)?","pt":"A organização possui um Centro de Excelência em Software Seguro (SSCE)?","gen":["The SSCE has a charter defining its role in the organization","Development teams review all significant architectural changes with the SSCE","The SSCE publishes SDLC standards and guidelines related to Application Security","Product Champions are responsible for promoting the use of specific security tools"],"gpt":["O SSCE tem um charter que define seu papel na organização","As equipes revisam todas as mudanças arquiteturais significativas com o SSCE","O SSCE publica padrões e diretrizes de SDLC relacionados à AppSec","Product Champions são responsáveis por promover o uso de ferramentas de segurança específicas"]},{"stream":"A","level":3,"en":"Have you implemented a Learning Management System or equivalent to track employee training and certification processes?","pt":"Vocês implementaram um LMS (ou equivalente) para acompanhar os processos de treinamento e certificação dos funcionários?","gen":["A Learning Management System (LMS) is used to track trainings and certifications","Training is based on internal standards, policies, and procedures","You use certification programs or attendance records to determine access to development systems and resources"],"gpt":["Um LMS é usado para acompanhar treinamentos e certificações","O treinamento é baseado em padrões, políticas e procedimentos internos","Vocês usam certificações ou registros de presença para definir acesso a sistemas e recursos de desenvolvimento"]},{"stream":"B","level":3,"en":"Is there a centralized portal where developers and application security professionals from different teams and business units are able to communicate and share information?","pt":"Existe um portal centralizado onde desenvolvedores e profissionais de segurança de diferentes equipes e unidades de negócio possam se comunicar e compartilhar informações?","gen":["The organization promotes use of a single portal across different teams and business units","The portal is used for timely information such as notification of security incidents, tool updates, architectural standard changes, and other related announcements","The portal is widely recognized by developers and architects as a centralized repository of the organization-specific application security information","All content is considered persistent and searchable"],"gpt":["A organização promove o uso de um portal único entre equipes e unidades de negócio","O portal é usado para informações oportunas: notificação de incidentes, atualizações de ferramentas, mudanças de padrões arquiteturais e demais avisos","É amplamente reconhecido por desenvolvedores e arquitetos como repositório centralizado de informações de AppSec","Todo o conteúdo é persistente e pesquisável"]}]}]},{"name":"Design","pt":"Design","code":"D","practices":[{"name":"Threat Assessment","pt":"Avaliação de Ameaças","code":"TA","A":{"en":"Application Risk Profile","pt":"Perfil de Risco da Aplicação"},"B":{"en":"Threat Modeling","pt":"Modelagem de Ameaças"},"questions":[{"stream":"A","level":1,"en":"Do you classify applications according to business risk based on a simple and predefined set of questions?","pt":"Vocês classificam aplicações conforme o risco de negócio com base em um conjunto simples e predefinido de perguntas?","gen":["An agreed-upon risk classification exists","The application team understands the risk classification","The risk classification covers critical aspects of business risks the organization is facing","The organization has an inventory for the applications in scope"],"gpt":["Existe uma classificação de risco acordada","A equipe da aplicação entende a classificação de risco","A classificação cobre os aspectos críticos dos riscos de negócio que a organização enfrenta","A organização tem um inventário das aplicações em escopo"]},{"stream":"B","level":1,"en":"Do you identify and manage architectural design flaws with threat modeling?","pt":"Vocês identificam e gerenciam falhas de design arquitetural com modelagem de ameaças?","gen":["You perform threat modeling for high-risk applications","You use simple threat checklists, such as STRIDE","You persist the outcome of a threat model for later use"],"gpt":["Vocês fazem modelagem de ameaças para aplicações de alto risco","Vocês usam checklists simples de ameaças, como STRIDE","Vocês preservam o resultado do threat model para uso posterior"]},{"stream":"A","level":2,"en":"Do you use centralized and quantified application risk profiles to evaluate business risk?","pt":"Vocês usam perfis de risco de aplicação centralizados e quantificados para avaliar o risco de negócio?","gen":["The application risk profile is in line with the organizational risk standard","The application risk profile covers impact to security and privacy","You validate the quality of the risk profile manually and/or automatically","The application risk profiles are stored in a central inventory"],"gpt":["O perfil de risco da aplicação está alinhado ao padrão de risco organizacional","O perfil cobre impacto à segurança e à privacidade","Vocês validam a qualidade do perfil de risco manual e/ou automaticamente","Os perfis de risco ficam em um inventário central"]},{"stream":"B","level":2,"en":"Do you use a standard methodology, aligned with your application risk levels?","pt":"Vocês usam uma metodologia padrão, alinhada aos níveis de risco das suas aplicações?","gen":["You train your architects, security champions, and other stakeholders on how to do practical threat modeling","Your threat modeling methodology includes at least diagramming, threat identification, design flaw mitigations, and how to validate your threat model artifacts","Changes in the application or business context trigger a review of the relevant threat models","You capture the threat modeling artifacts with tools used by your application teams"],"gpt":["Vocês treinam arquitetos, security champions e demais stakeholders em modelagem de ameaças prática","A metodologia inclui ao menos diagramação, identificação de ameaças, mitigação de falhas de design e validação dos artefatos","Mudanças na aplicação ou no contexto de negócio disparam a revisão dos threat models relevantes","Vocês registram os artefatos com as ferramentas usadas pelas equipes"]},{"stream":"A","level":3,"en":"Do you regularly review and update the risk profiles for your applications?","pt":"Vocês revisam e atualizam regularmente os perfis de risco das suas aplicações?","gen":["The organizational risk standard considers historical feedback to improve the evaluation method","Significant changes in the application or business context trigger a review of the relevant risk profiles"],"gpt":["O padrão de risco organizacional considera feedback histórico para melhorar o método de avaliação","Mudanças significativas na aplicação ou no contexto de negócio disparam a revisão dos perfis de risco relevantes"]},{"stream":"B","level":3,"en":"Do you regularly review and update the threat modeling methodology for your applications?","pt":"Vocês revisam e atualizam regularmente a metodologia de modelagem de ameaças das suas aplicações?","gen":["The threat model methodology considers historical feedback for improvement","You regularly (e.g., yearly) review the existing threat models to verify that no new threats are relevant for your applications","You automate parts of your threat modeling process with threat modeling tools"],"gpt":["A metodologia de threat model considera feedback histórico para melhoria","Vocês revisam regularmente (ex.: anualmente) os threat models existentes para verificar novas ameaças relevantes","Vocês automatizam partes do processo com ferramentas de modelagem de ameaças"]}]},{"name":"Security Requirements","pt":"Requisitos de Segurança","code":"SR","A":{"en":"Software Requirements","pt":"Requisitos de Software"},"B":{"en":"Supplier Security","pt":"Segurança de Fornecedores"},"questions":[{"stream":"A","level":1,"en":"Do project teams specify security requirements during development?","pt":"As equipes de projeto especificam requisitos de segurança durante o desenvolvimento?","gen":["Teams derive security requirements from functional requirements and customer or organization concerns","Security requirements are specific, measurable, and reasonable","Security requirements are in line with the organizational baseline"],"gpt":["As equipes derivam requisitos de segurança dos requisitos funcionais e das preocupações do cliente/organização","Os requisitos de segurança são específicos, mensuráveis e razoáveis","Os requisitos de segurança estão alinhados ao baseline organizacional"]},{"stream":"B","level":1,"en":"Do stakeholders review vendor collaborations for security requirements and methodology?","pt":"Os stakeholders revisam as colaborações com fornecedores quanto a requisitos e metodologia de segurança?","gen":["You consider including specific security requirements, activities, and processes when creating third-party agreements","A vendor questionnaire is available and used to assess the strengths and weaknesses of your suppliers"],"gpt":["Vocês consideram incluir requisitos, atividades e processos de segurança específicos ao criar acordos com terceiros","Há um questionário de fornecedor disponível e usado para avaliar forças e fraquezas dos fornecedores"]},{"stream":"A","level":2,"en":"Do you define, structure, and include prioritization in the artifacts of the security requirements gathering process?","pt":"Vocês definem, estruturam e priorizam os artefatos do processo de levantamento de requisitos de segurança?","gen":["Security requirements take into consideration domain specific knowledge when applying policies and guidance to product development","Domain experts are involved in the requirements definition process","You have an agreed upon structured notation for security requirements","Development teams have a security champion dedicated to reviewing security requirements and outcomes"],"gpt":["Os requisitos de segurança consideram conhecimento específico do domínio ao aplicar políticas e orientações ao desenvolvimento do produto","Especialistas de domínio participam do processo de definição de requisitos","Há uma notação estruturada acordada para requisitos de segurança","As equipes de desenvolvimento têm um security champion dedicado a revisar requisitos e resultados de segurança"]},{"stream":"B","level":2,"en":"Do vendors meet the security responsibilities and quality measures of service level agreements defined by the organization?","pt":"Os fornecedores cumprem as responsabilidades de segurança e medidas de qualidade dos SLAs definidos pela organização?","gen":["You discuss security requirements with the vendor when creating vendor agreements","Vendor agreements provide specific guidance on security defect remediation within an agreed upon timeframe","The organization has a templated agreement of responsibilities and service levels for key vendor security processes","You measure key performance indicators"],"gpt":["Vocês discutem requisitos de segurança com o fornecedor ao criar os acordos","Os acordos fornecem orientação específica sobre correção de defeitos de segurança dentro de um prazo acordado","A organização tem um modelo de acordo de responsabilidades e níveis de serviço para os processos-chave de segurança do fornecedor","Vocês medem indicadores-chave de desempenho"]},{"stream":"A","level":3,"en":"Do you use a standard requirements framework to streamline the elicitation of security requirements?","pt":"Vocês usam um framework padrão de requisitos para agilizar a elicitação de requisitos de segurança?","gen":["A security requirements framework is available for project teams","The framework is categorized by common requirements and standards-based requirements","The framework gives clear guidance on the quality of requirements and how to describe them","The framework is adaptable to specific business requirements"],"gpt":["Há um framework de requisitos de segurança disponível para as equipes","O framework é categorizado por requisitos comuns e requisitos baseados em padrões","O framework dá orientação clara sobre a qualidade dos requisitos e como descrevê-los","O framework é adaptável a requisitos de negócio específicos"]},{"stream":"B","level":3,"en":"Are vendors aligned with standard security controls and software development tools and processes that the organization utilizes?","pt":"Os fornecedores estão alinhados aos controles de segurança e ferramentas/processos de desenvolvimento padrão usados pela organização?","gen":["The vendor has a secure SDLC that includes secure build, secure deployment, defect management, and incident management, meets the security expectations of your organization, and is able to demonstrate operating effectiveness of practices.","You verify the solution meets quality and security objectives before every major release","When standard verification processes are not available, you use compensating controls such as software composition analysis and independent penetration testing"],"gpt":["O fornecedor tem um SDLC seguro (build seguro, deploy seguro, gestão de defeitos e de incidentes), atende às expectativas de segurança da organização e demonstra eficácia operacional","Vocês verificam que a solução atende aos objetivos de qualidade e segurança antes de cada release importante","Quando não há processos de verificação padrão, vocês usam controles compensatórios como análise de composição de software e pentest independente"]}]},{"name":"Secure Architecture","pt":"Arquitetura Segura","code":"SA","A":{"en":"Architecture Design","pt":"Projeto de Arquitetura"},"B":{"en":"Technology Management","pt":"Gestão de Tecnologia"},"questions":[{"stream":"A","level":1,"en":"Do teams use security principles during design?","pt":"As equipes utilizam princípios de segurança durante o design?","gen":["You have an agreed upon checklist of security principles","You store your checklist in an accessible location","Relevant stakeholders understand security principles"],"gpt":["Existe um checklist de princípios de segurança acordado","O checklist fica armazenado em local acessível","Os stakeholders relevantes entendem os princípios de segurança"]},{"stream":"B","level":1,"en":"Do you evaluate the security quality of important technologies used for development?","pt":"Vocês avaliam a qualidade de segurança das tecnologias importantes usadas no desenvolvimento?","gen":["You have a list of the most important technologies used in, or in support of, each application","You identify and track technological risks","You ensure the risks to these technologies are in line with the organizational baseline"],"gpt":["Há uma lista das tecnologias mais importantes usadas em (ou para apoiar) cada aplicação","Vocês identificam e acompanham os riscos tecnológicos","Vocês garantem que os riscos dessas tecnologias estejam alinhados ao baseline organizacional"]},{"stream":"A","level":2,"en":"Do you use shared security services during design?","pt":"Vocês utilizam serviços de segurança compartilhados durante o design?","gen":["You have a documented list of reusable security services, available to relevant stakeholders","You have reviewed the baseline security posture for each selected service","Your designers are trained to integrate each selected service following available guidance"],"gpt":["Há uma lista documentada de serviços de segurança reutilizáveis, disponível aos stakeholders","A postura de segurança baseline de cada serviço selecionado foi revisada","Os designers são treinados para integrar cada serviço seguindo a orientação disponível"]},{"stream":"B","level":2,"en":"Do you have a list of recommended technologies for the organization?","pt":"Vocês têm uma lista de tecnologias recomendadas para a organização?","gen":["The list is based on technologies used in the software portfolio","Lead architects and developers review and approve the list","You share the list across the organization","You review and update the list at least yearly"],"gpt":["A lista é baseada nas tecnologias usadas no portfólio de software","Arquitetos e desenvolvedores líderes revisam e aprovam a lista","A lista é compartilhada por toda a organização","A lista é revisada e atualizada pelo menos anualmente"]},{"stream":"A","level":3,"en":"Do you base your design on available reference architectures?","pt":"Vocês baseiam seu design em arquiteturas de referência disponíveis?","gen":["You have one or more approved reference architectures documented and available to stakeholders","You improve the reference architectures continuously based on insights and best practices","You provide a set of components, libraries, and tools to implement each reference architecture"],"gpt":["Há uma ou mais arquiteturas de referência aprovadas, documentadas e disponíveis aos stakeholders","As arquiteturas de referência são melhoradas continuamente com base em insights e boas práticas","Vocês fornecem um conjunto de componentes, bibliotecas e ferramentas para implementar cada arquitetura de referência"]},{"stream":"B","level":3,"en":"Do you enforce the use of recommended technologies within the organization?","pt":"Vocês impõem o uso das tecnologias recomendadas dentro da organização?","gen":["You monitor applications regularly for the correct use of the recommended technologies","You solve violations against the list accoranding to organizational policies","You take action if the number of violations falls outside the yearly objectives"],"gpt":["Vocês monitoram regularmente as aplicações quanto ao uso correto das tecnologias recomendadas","Vocês resolvem violações à lista conforme as políticas organizacionais","Vocês agem quando o número de violações foge dos objetivos anuais"]}]}]},{"name":"Implementation","pt":"Implementação","code":"I","practices":[{"name":"Secure Build","pt":"Build Seguro","code":"SB","A":{"en":"Build Process","pt":"Processo de Build"},"B":{"en":"Software Dependencies","pt":"Dependências de Software"},"questions":[{"stream":"A","level":1,"en":"Is your full build process formally described?","pt":"Seu processo de build completo está formalmente descrito?","gen":["You have enough information to recreate the build processes","Your build documentation up to date","Your build documentation is stored in an accessible location","Produced artifact checksums are created during build to support later verification"],"gpt":["Há informação suficiente para recriar os processos de build","A documentação de build está atualizada","A documentação fica em local acessível","Checksums dos artefatos são gerados durante o build para verificação posterior"]},{"stream":"B","level":1,"en":"Do you have solid knowledge about dependencies you're relying on?","pt":"Vocês têm conhecimento sólido sobre as dependências das quais dependem?","gen":["You have a current bill of materials (BOM) for every application","You can quickly find out which applications are affected by a particular CVE","You have analyzed, addressed, and documented findings from dependencies at least once in the last three months"],"gpt":["Há um bill of materials (BOM) atual para cada aplicação","Vocês descobrem rapidamente quais aplicações são afetadas por um CVE específico","Vocês analisaram, trataram e documentaram achados de dependências ao menos uma vez nos últimos três meses"]},{"stream":"A","level":2,"en":"Is the build process fully automated?","pt":"O processo de build é totalmente automatizado?","gen":["The build process itself doesn't require any human interaction","Your build tools are hardened as per best practice and vendor guidance","You encrypt the secrets required by the build tools and control access based on the principle of least privilege"],"gpt":["O processo de build não exige interação humana","As ferramentas de build têm hardening conforme boas práticas e orientação do fornecedor","Vocês criptografam os segredos exigidos pelas ferramentas e controlam o acesso pelo menor privilégio"]},{"stream":"B","level":2,"en":"Do you handle 3rd party dependency risk by a formal process?","pt":"Vocês tratam o risco de dependências de terceiros por meio de um processo formal?","gen":["You keep a list of approved dependencies that meet predefined criteria","You automatically evaluate dependencies for new CVEs and alert responsible staff","You automatically detect and alert to license changes with possible impact on legal application usage","You track and alert to usage of unmaintained dependencies"],"gpt":["Vocês mantêm uma lista de dependências aprovadas que atendem a critérios predefinidos","Vocês avaliam dependências automaticamente quanto a novos CVEs e alertam os responsáveis","Vocês detectam e alertam automaticamente mudanças de licença com possível impacto legal","Vocês rastreiam e alertam o uso de dependências sem manutenção"]},{"stream":"A","level":3,"en":"Do you enforce automated security checks in your build processes?","pt":"Vocês impõem verificações de segurança automatizadas nos seus processos de build?","gen":["Builds fail if the application doesn't meet a predefined security baseline","You have a maximum accepted severity for vulnerabilities","You log warnings and failures in a centralized system","You select and configure tools to evaluate each application against its security requirements at least once a year"],"gpt":["O build falha se a aplicação não atende a um baseline de segurança predefinido","Há uma severidade máxima aceita para vulnerabilidades","Vocês registram avisos e falhas em um sistema centralizado","Vocês selecionam e configuram ferramentas para avaliar cada aplicação contra seus requisitos ao menos uma vez por ano"]},{"stream":"B","level":3,"en":"Do you prevent build of software if it's affected by vulnerabilities in dependencies?","pt":"Vocês impedem o build de software se ele for afetado por vulnerabilidades em dependências?","gen":["Your build system is connected to a system for tracking 3rd party dependency risk, causing build to fail unless the vulnerability is evaluated to be a false positive or the risk is explicitly accepted","You scan your dependencies using a static analysis tool","You report findings back to dependency authors using an established responsible disclosure process","Using a new dependency not evaluated for security risks causes the build to fail"],"gpt":["O sistema de build é conectado a um sistema de risco de dependências de terceiros, falhando o build a menos que a vulnerabilidade seja falso positivo ou o risco seja explicitamente aceito","Vocês escaneiam as dependências com ferramenta de análise estática","Vocês reportam achados aos autores das dependências via processo de divulgação responsável","Usar uma nova dependência não avaliada quanto a riscos faz o build falhar"]}]},{"name":"Secure Deployment","pt":"Deploy Seguro","code":"SD","A":{"en":"Deployment Process","pt":"Processo de Deploy"},"B":{"en":"Secret Management","pt":"Gestão de Segredos"},"questions":[{"stream":"A","level":1,"en":"Do you use repeatable deployment processes?","pt":"Vocês usam processos de deploy repetíveis?","gen":["You have enough information to run the deployment processes","Your deployment documentation up to date","Your deployment documentation is accessible to relevant stakeholders","You ensure that only defined qualified personnel can trigger a deployment"],"gpt":["Há informação suficiente para executar os processos de deploy","A documentação de deploy está atualizada","A documentação é acessível aos stakeholders relevantes","Apenas pessoal qualificado e definido pode disparar um deploy"]},{"stream":"B","level":1,"en":"Do you limit access to application secrets according to the least privilege principle?","pt":"Vocês limitam o acesso aos segredos da aplicação conforme o princípio do menor privilégio?","gen":["You store production secrets protected in a secured location","Developers do not have access to production secrets","Production secrets are not available in non-production environments"],"gpt":["Vocês armazenam os segredos de produção protegidos em local seguro","Os desenvolvedores não têm acesso aos segredos de produção","Os segredos de produção não estão disponíveis em ambientes de não-produção"]},{"stream":"A","level":2,"en":"Are deployment processes automated and employing security checks?","pt":"Os processos de deploy são automatizados e empregam verificações de segurança?","gen":["Deployment processes are automated on all stages","Deployment includes automated security testing procedures","You alert responsible staff to identified vulnerabilities","You have logs available for your past deployments for a defined period of time"],"gpt":["Os processos de deploy são automatizados em todos os estágios","O deploy inclui procedimentos automatizados de teste de segurança","Vocês alertam os responsáveis sobre vulnerabilidades identificadas","Vocês mantêm logs dos deploys passados por um período definido"]},{"stream":"B","level":2,"en":"Do you inject production secrets into configuration files during deployment?","pt":"Vocês injetam segredos de produção nos arquivos de configuração durante o deploy?","gen":["Source code files no longer contain active application secrets","Under normal circumstances, no humans access secrets during deployment procedures","You log and alert when abnormal secrets access is attempted"],"gpt":["Os arquivos de código-fonte não contêm mais segredos ativos da aplicação","Em circunstâncias normais, nenhum humano acessa segredos durante o deploy","Vocês registram e alertam quando há tentativa anormal de acesso a segredos"]},{"stream":"A","level":3,"en":"Do you consistently validate the integrity of deployed artifacts?","pt":"Vocês validam consistentemente a integridade dos artefatos implantados?","gen":["You prevent or roll back deployment if you detect an integrity breach","The verification is done against signatures created during the build time","If checking of signatures is not possible (e.g. externally build software), you introduce compensating measures"],"gpt":["Vocês impedem ou revertem o deploy ao detectar violação de integridade","A verificação é feita contra assinaturas criadas no momento do build","Quando checar assinaturas não é possível (ex.: software de terceiros), vocês adotam medidas compensatórias"]},{"stream":"B","level":3,"en":"Do you practice proper lifecycle management for application secrets?","pt":"Vocês praticam a gestão adequada do ciclo de vida dos segredos da aplicação?","gen":["You generate and synchronize secrets using a vetted solution","Secrets are different between different application instances","Secrets are regularly updated"],"gpt":["Vocês geram e sincronizam segredos usando uma solução validada","Os segredos são diferentes entre instâncias distintas da aplicação","Os segredos são atualizados regularmente"]}]},{"name":"Defect Management","pt":"Gestão de Defeitos","code":"DM","A":{"en":"Defect Tracking","pt":"Rastreamento de Defeitos"},"B":{"en":"Metrics and Feedback","pt":"Métricas e Feedback"},"questions":[{"stream":"A","level":1,"en":"Do you track all known security defects in accessible locations?","pt":"Vocês rastreiam todos os defeitos de segurança conhecidos em locais acessíveis?","gen":["You can easily get an overview of all security defects impacting one application","You have at least a rudimentary classification scheme in place","The process includes a strategy for handling false positives and duplicate entries","The defect management system covers defects from various sources and activities"],"gpt":["É fácil obter uma visão geral de todos os defeitos de segurança que afetam uma aplicação","Há ao menos um esquema rudimentar de classificação","O processo inclui estratégia para falsos positivos e entradas duplicadas","O sistema cobre defeitos de várias fontes e atividades"]},{"stream":"B","level":1,"en":"Do you use basic metrics about recorded security defects to carry out quick win improvement activities?","pt":"Vocês usam métricas básicas sobre defeitos de segurança registrados para executar melhorias de ganho rápido?","gen":["You analyzed your recorded metrics at least once in the last year","At least basic information about this initiative is recorded and available","You have identified and carried out at least one quick win activity based on the data"],"gpt":["Vocês analisaram as métricas registradas ao menos uma vez no último ano","Ao menos informações básicas sobre essa iniciativa são registradas e disponíveis","Vocês identificaram e executaram ao menos uma ação de ganho rápido com base nos dados"]},{"stream":"A","level":2,"en":"Do you keep an overview of the state of security defects across the organization?","pt":"Vocês mantêm uma visão geral do estado dos defeitos de segurança em toda a organização?","gen":["A single severity scheme is applied to all defects across the organization","The scheme includes SLAs for fixing particular severity classes","You regularly report compliance to SLAs"],"gpt":["Um único esquema de severidade é aplicado a todos os defeitos na organização","O esquema inclui SLAs para corrigir cada classe de severidade","Vocês reportam regularmente a conformidade com os SLAs"]},{"stream":"B","level":2,"en":"Do you improve your security assurance program upon standardized metrics?","pt":"Vocês aprimoram seu programa de garantia de segurança com base em métricas padronizadas?","gen":["You document metrics for defect classification and categorization and keep them up to date","Executive management regularly receives information about defects and has acted upon it in the last year","You regularly share technical details about security defects among teams"],"gpt":["Vocês documentam e mantêm atualizadas as métricas de classificação e categorização de defeitos","A alta gestão recebe regularmente informação sobre defeitos e agiu sobre ela no último ano","Vocês compartilham regularmente detalhes técnicos dos defeitos entre as equipes"]},{"stream":"A","level":3,"en":"Do you enforce SLAs for fixing security defects?","pt":"Vocês impõem SLAs para a correção de defeitos de segurança?","gen":["You automatically alert of SLA breaches and transfer respective defects to the risk management process","You integrate relevant tooling (e.g. monitoring, build, deployment) with the defect management system"],"gpt":["Vocês alertam automaticamente sobre violações de SLA e transferem os defeitos ao processo de gestão de risco","Vocês integram ferramentas relevantes (monitoramento, build, deploy) ao sistema de gestão de defeitos"]},{"stream":"B","level":3,"en":"Do you regularly evaluate the effectiveness of your security metrics so that its input helps drive your security strategy?","pt":"Vocês avaliam regularmente a eficácia das suas métricas de segurança para que elas ajudem a direcionar a estratégia de segurança?","gen":["You have analyzed the effectiveness of the security metrics at least once in the last year","Where possible, you verify the correctness of the data automatically","The metrics is aggregated with other sources like threat intelligence or incident management","You derived at least one strategic activity from the metrics in the last year"],"gpt":["Vocês analisaram a eficácia das métricas de segurança ao menos uma vez no último ano","Quando possível, vocês verificam a correção dos dados automaticamente","As métricas são agregadas a outras fontes, como threat intelligence ou gestão de incidentes","Vocês derivaram ao menos uma atividade estratégica das métricas no último ano"]}]}]},{"name":"Verification","pt":"Verificação","code":"V","practices":[{"name":"Architecture Assessment","pt":"Avaliação de Arquitetura","code":"AA","A":{"en":"Architecture Validation","pt":"Validação de Arquitetura"},"B":{"en":"Architecture Mitigation","pt":"Mitigação de Arquitetura"},"questions":[{"stream":"A","level":1,"en":"Do you review the application architecture for key security objectives on an ad-hoc basis?","pt":"Vocês revisam a arquitetura da aplicação quanto aos principais objetivos de segurança de forma ad-hoc?","gen":["You have an agreed upon model of the overall software architecture","You include components, interfaces, and integrations in the architecture model","You verify the correct provision of general security mechanisms","You log missing security controls as defects"],"gpt":["Há um modelo acordado da arquitetura geral do software","O modelo inclui componentes, interfaces e integrações","Vocês verificam a provisão correta dos mecanismos gerais de segurança","Vocês registram controles de segurança ausentes como defeitos"]},{"stream":"B","level":1,"en":"Do you review the application architecture for mitigations of typical threats on an ad-hoc basis?","pt":"Vocês revisam a arquitetura da aplicação quanto às mitigações de ameaças típicas de forma ad-hoc?","gen":["You have an agreed upon model of the overall software architecture","Security savvy staff conduct the review","You consider different types of threats, including insider and data-related ones"],"gpt":["Há um modelo acordado da arquitetura geral do software","Pessoal com conhecimento de segurança conduz a revisão","Vocês consideram diferentes tipos de ameaças, incluindo internas e relacionadas a dados"]},{"stream":"A","level":2,"en":"Do you regularly review the security mechanisms of your architecture?","pt":"Vocês revisam regularmente os mecanismos de segurança da sua arquitetura?","gen":["You review compliance with internal and external requirements","You systematically review each interface in the system","You use a formalized review method and structured validation","You log missing security mechanisms as defects"],"gpt":["Vocês revisam a conformidade com requisitos internos e externos","Vocês revisam sistematicamente cada interface do sistema","Vocês usam um método formalizado de revisão e validação estruturada","Vocês registram mecanismos de segurança ausentes como defeitos"]},{"stream":"B","level":2,"en":"Do you regularly evaluate the threats to your architecture?","pt":"Vocês avaliam regularmente as ameaças à sua arquitetura?","gen":["You systematically review each threat identified in the Threat Assessment","Trained or experienced people lead review exercise","You identify mitigating design-level features for each identified threat","You log unhandled threats as defects"],"gpt":["Vocês revisam sistematicamente cada ameaça identificada na Avaliação de Ameaças","Pessoas treinadas ou experientes lideram o exercício de revisão","Vocês identificam funcionalidades de mitigação no nível de design para cada ameaça","Vocês registram ameaças não tratadas como defeitos"]},{"stream":"A","level":3,"en":"Do you regularly review the effectiveness of the security controls?","pt":"Vocês revisam regularmente a eficácia dos controles de segurança?","gen":["You evaluate the preventive, detective, and response capabilities of security controls","You evaluate the strategy alignment, appropriate support, and scalability of security controls","You evaluate the effectiveness at least yearly","You log identified shortcomings as defects"],"gpt":["Vocês avaliam as capacidades preventivas, detectivas e de resposta dos controles","Vocês avaliam alinhamento estratégico, suporte adequado e escalabilidade dos controles","Vocês avaliam a eficácia ao menos anualmente","Vocês registram deficiências identificadas como defeitos"]},{"stream":"B","level":3,"en":"Do you regularly update your reference architectures based on architecture assessment findings?","pt":"Vocês atualizam regularmente suas arquiteturas de referência com base nos achados das avaliações de arquitetura?","gen":["You assess your architectures in a standardized, documented manner","You use recurring findings to trigger a review of reference architectures","You independently review the quality of the architecture assessments on an ad-hoc basis","You use reference architecture updates to trigger reviews of relevant shared solutions, in a risk-based manner"],"gpt":["Vocês avaliam suas arquiteturas de forma padronizada e documentada","Vocês usam achados recorrentes para disparar a revisão das arquiteturas de referência","Vocês revisam independentemente a qualidade das avaliações de arquitetura de forma ad-hoc","Atualizações da arquitetura de referência disparam revisões das soluções compartilhadas relevantes, de forma baseada em risco"]}]},{"name":"Requirements-driven Testing","pt":"Testes Orientados a Requisitos","code":"RT","A":{"en":"Control Verification","pt":"Verificação de Controles"},"B":{"en":"Misuse/Abuse Testing","pt":"Testes de Uso Indevido/Abuso"},"questions":[{"stream":"A","level":1,"en":"Do you test applications for the correct functioning of standard security controls?","pt":"Vocês testam as aplicações quanto ao funcionamento correto dos controles de segurança padrão?","gen":["Security testing at least verifies the implementation of authentication, access control, input validation, encoding and escaping data, and encryption controls","Security testing executes whenever the application changes its use of the controls"],"gpt":["O teste de segurança verifica ao menos autenticação, controle de acesso, validação de entrada, codificação/escape de dados e controles de criptografia","O teste é executado sempre que a aplicação muda o uso desses controles"]},{"stream":"B","level":1,"en":"Do you test applications using randomization or fuzzing techniques?","pt":"Vocês testam as aplicações usando técnicas de randomização ou fuzzing?","gen":["Testing covers most or all of the application's main input parameters","You record and inspect all application crashes for security impact on a best-effort basis"],"gpt":["O teste cobre a maioria ou todos os principais parâmetros de entrada da aplicação","Vocês registram e inspecionam todos os crashes quanto a impacto de segurança, na medida do possível"]},{"stream":"A","level":2,"en":"Do you consistently write and execute test scripts to verify the functionality of security requirements?","pt":"Vocês escrevem e executam consistentemente scripts de teste para verificar a funcionalidade dos requisitos de segurança?","gen":["You tailor tests to each application and assert expected security functionality","You capture test results as a pass or fail condition","Tests use a standardized framework or DSL"],"gpt":["Vocês adaptam os testes a cada aplicação e validam a funcionalidade de segurança esperada","Vocês capturam resultados como condição de aprovado/reprovado","Os testes usam um framework ou DSL padronizado"]},{"stream":"B","level":2,"en":"Do you create abuse cases from functional requirements and use them to drive security tests?","pt":"Vocês criam casos de abuso a partir dos requisitos funcionais e os usam para conduzir testes de segurança?","gen":["Important business functionality has corresponding abuse cases","You build abuse stories around relevant personas with well-defined motivations and characteristics","You capture identified weaknesses as security requirements"],"gpt":["As funcionalidades de negócio importantes têm casos de abuso correspondentes","Vocês criam histórias de abuso em torno de personas relevantes com motivações e características bem definidas","Vocês capturam fraquezas identificadas como requisitos de segurança"]},{"stream":"A","level":3,"en":"Do you automatically test applications for security regressions?","pt":"Vocês testam automaticamente as aplicações quanto a regressões de segurança?","gen":["You consistently write tests for all identified bugs (possibly exceeding a pre-defined severity threshold)","You collect security tests in a test suite that is part of the existing unit testing framework"],"gpt":["Vocês escrevem testes consistentemente para todos os bugs identificados (possivelmente acima de um limite de severidade)","Vocês reúnem os testes de segurança em uma suíte que faz parte do framework de testes unitários existente"]},{"stream":"B","level":3,"en":"Do you perform denial of service and security stress testing?","pt":"Vocês realizam testes de negação de serviço e de estresse de segurança?","gen":["Stress tests target specific application resources (e.g. memory exhaustion by saving large amounts of data to a user session)","You design tests around relevant personas with well-defined capabilities (knowledge, resources)","You feed the results back to the Design practices"],"gpt":["Os testes de estresse miram recursos específicos da aplicação (ex.: esgotamento de memória salvando muitos dados na sessão)","Vocês desenham testes em torno de personas com capacidades bem definidas (conhecimento, recursos)","Vocês realimentam os resultados nas práticas de Design"]}]},{"name":"Security Testing","pt":"Testes de Segurança","code":"ST","A":{"en":"Scalable Baseline","pt":"Baseline Escalável"},"B":{"en":"Deep Understanding","pt":"Entendimento Profundo"},"questions":[{"stream":"A","level":1,"en":"Do you scan applications with automated security testing tools?","pt":"Vocês escaneiam as aplicações com ferramentas automatizadas de teste de segurança?","gen":["You dynamically generate inputs for security tests using automated tools","You choose the security testing tools to fit the organization's architecture and technology stack, and balance depth and accuracy of inspection with usability of findings to the organization"],"gpt":["Vocês geram entradas dinamicamente para os testes de segurança usando ferramentas automatizadas","Vocês escolhem as ferramentas conforme a arquitetura e a stack da organização, equilibrando profundidade/acurácia com a usabilidade dos achados"]},{"stream":"B","level":1,"en":"Do you manually review the security quality of selected high-risk components?","pt":"Vocês revisam manualmente a qualidade de segurança de componentes selecionados de alto risco?","gen":["Criteria exist to help the reviewer focus on high-risk components","Qualified personnel conduct reviews following documented guidelines","You address findings in accordance with the organization's defect management policy"],"gpt":["Existem critérios para o revisor focar nos componentes de alto risco","Pessoal qualificado conduz as revisões seguindo diretrizes documentadas","Vocês tratam os achados conforme a política de gestão de defeitos da organização"]},{"stream":"A","level":2,"en":"Do you customize the automated security tools to your applications and technology stacks?","pt":"Vocês customizam as ferramentas automatizadas de segurança para suas aplicações e stacks tecnológicas?","gen":["You tune and select tool features which match your application or technology stack","You minimize false positives by silencing or automatically filter irrelevant warnings or low probability findings","You minimize false negatives by leverage tool extensions or DSLs to customize tools for your application or organizational standards"],"gpt":["Vocês ajustam e selecionam recursos da ferramenta que combinam com sua aplicação ou stack","Vocês minimizam falsos positivos silenciando ou filtrando automaticamente avisos irrelevantes ou de baixa probabilidade","Vocês minimizam falsos negativos usando extensões ou DSLs para customizar as ferramentas aos seus padrões"]},{"stream":"B","level":2,"en":"Do you perform penetration testing for your applications at regular intervals?","pt":"Vocês realizam testes de penetração nas suas aplicações em intervalos regulares?","gen":["Penetration testing uses application-specific security test cases to evaluate security","Penetration testing looks for both technical and logical issues in the application","Stakeholders review the test results and handle them in accordance with the organization's risk management","Qualified personnel performs penetration testing"],"gpt":["O pentest usa casos de teste de segurança específicos da aplicação","O pentest busca problemas técnicos e lógicos na aplicação","Os stakeholders revisam os resultados e os tratam conforme a gestão de risco da organização","Pessoal qualificado realiza o pentest"]},{"stream":"A","level":3,"en":"Do you integrate automated security testing into the build and deploy process?","pt":"Vocês integram testes de segurança automatizados ao processo de build e deploy?","gen":["Management and business stakeholders track and review test results throughout the development cycle","You merge test results into a central dashboard and feed them into defect management"],"gpt":["Gestão e stakeholders de negócio acompanham e revisam os resultados ao longo do ciclo de desenvolvimento","Vocês reúnem os resultados em um dashboard central e os alimentam na gestão de defeitos"]},{"stream":"B","level":3,"en":"Do you use the results of security testing to improve the development lifecycle?","pt":"Vocês usam os resultados dos testes de segurança para melhorar o ciclo de desenvolvimento?","gen":["You use results from other security activities to improve integrated security testing during development","You review test results and incorporate them into security awareness training and security testing playbooks","Stakeholders review the test results and handle them in accordance with the organization's risk management"],"gpt":["Vocês usam resultados de outras atividades de segurança para melhorar o teste integrado durante o desenvolvimento","Vocês revisam os resultados e os incorporam ao treinamento de conscientização e aos playbooks de teste","Os stakeholders revisam os resultados e os tratam conforme a gestão de risco da organização"]}]}]},{"name":"Operations","pt":"Operações","code":"O","practices":[{"name":"Incident Management","pt":"Gestão de Incidentes","code":"IM","A":{"en":"Incident Detection","pt":"Detecção de Incidentes"},"B":{"en":"Incident Response","pt":"Resposta a Incidentes"},"questions":[{"stream":"A","level":1,"en":"Do you analyze log data for security incidents periodically?","pt":"Vocês analisam dados de log em busca de incidentes de segurança periodicamente?","gen":["You have a contact point for the creation of security incidents","You analyze data in accordance with the log data retention periods","The frequency of this analysis is aligned with the criticality of your applications"],"gpt":["Há um ponto de contato para a criação de incidentes de segurança","Vocês analisam dados conforme os períodos de retenção de logs","A frequência da análise é alinhada à criticidade das aplicações"]},{"stream":"B","level":1,"en":"Do you respond to detected incidents?","pt":"Vocês respondem aos incidentes detectados?","gen":["You have a defined person or role for incident handling","You document security incidents"],"gpt":["Há uma pessoa ou papel definido para o tratamento de incidentes","Vocês documentam os incidentes de segurança"]},{"stream":"A","level":2,"en":"Do you follow a documented process for incident detection?","pt":"Vocês seguem um processo documentado para detecção de incidentes?","gen":["The process has a dedicated owner","You store process documentation in an accessible location","The process considers an escalation path for further analysis","You train employees responsible for incident detection in this process"],"gpt":["O processo tem um responsável dedicado","Vocês armazenam a documentação do processo em local acessível","O processo considera um caminho de escalonamento para análise adicional","Vocês treinam os responsáveis pela detecção de incidentes nesse processo"]},{"stream":"B","level":2,"en":"Do you use a repeatable process for incident handling?","pt":"Vocês usam um processo repetível para tratamento de incidentes?","gen":["You have an agreed upon incident classification","The process considers Root Cause Analysis for high severity incidents","Employees responsible for incident response are trained in this process","Forensic analysis tooling is available"],"gpt":["Há uma classificação de incidentes acordada","O processo considera Análise de Causa Raiz para incidentes de alta severidade","Os responsáveis pela resposta são treinados nesse processo","Há ferramentas de análise forense disponíveis"]},{"stream":"A","level":3,"en":"Do you review and update the incident detection process regularly?","pt":"Vocês revisam e atualizam regularmente o processo de detecção de incidentes?","gen":["You perform reviews at least annually","You update the checklist of potential attacks with external and internal data"],"gpt":["Vocês fazem revisões ao menos anualmente","Vocês atualizam o checklist de ataques potenciais com dados externos e internos"]},{"stream":"B","level":3,"en":"Do you have a dedicated incident response team available?","pt":"Vocês têm uma equipe dedicada de resposta a incidentes disponível?","gen":["The team performs Root Cause Analysis for all security incidents unless there is a specific reason not to do so","You review and update the response process at least annually"],"gpt":["A equipe faz Análise de Causa Raiz para todos os incidentes, salvo motivo específico em contrário","Vocês revisam e atualizam o processo de resposta ao menos anualmente"]}]},{"name":"Environment Management","pt":"Gestão de Ambiente","code":"EM","A":{"en":"Configuration Hardening","pt":"Hardening de Configuração"},"B":{"en":"Patching and Updating","pt":"Correção e Atualização"},"questions":[{"stream":"A","level":1,"en":"Do you harden configurations for key components of your technology stacks?","pt":"Vocês aplicam hardening nas configurações dos componentes-chave das suas stacks tecnológicas?","gen":["You have identified the key components in each technology stack used","You have an established configuration standard for each key component"],"gpt":["Vocês identificaram os componentes-chave de cada stack tecnológica usada","Há um padrão de configuração estabelecido para cada componente-chave"]},{"stream":"B","level":1,"en":"Do you identify and patch vulnerable components?","pt":"Vocês identificam e corrigem componentes vulneráveis?","gen":["You have an up-to-date list of components, including version information","You regularly review public sources for vulnerabilities related to your components"],"gpt":["Há uma lista atualizada de componentes, incluindo informação de versão","Vocês revisam regularmente fontes públicas de vulnerabilidades relacionadas aos seus componentes"]},{"stream":"A","level":2,"en":"Do you have hardening baselines for your components?","pt":"Vocês têm baselines de hardening para seus componentes?","gen":["You have assigned an owner for each baseline","The owner keeps their assigned baselines up to date","You store baselines in an accessible location","You train employees responsible for configurations in these baselines"],"gpt":["Há um responsável atribuído a cada baseline","O responsável mantém seus baselines atualizados","Os baselines ficam em local acessível","Vocês treinam os responsáveis por configuração nesses baselines"]},{"stream":"B","level":2,"en":"Do you follow an established process for updating components of your technology stacks?","pt":"Vocês seguem um processo estabelecido para atualizar componentes das suas stacks tecnológicas?","gen":["The process includes vendor information for third-party patches","The process considers external sources to gather information about zero day attacks, and includes appropriate risk mitigation steps","The process includes guidance for prioritizing component updates"],"gpt":["O processo inclui informação do fornecedor para patches de terceiros","O processo considera fontes externas para informação sobre ataques zero-day e inclui passos de mitigação de risco","O processo inclui orientação para priorizar atualizações de componentes"]},{"stream":"A","level":3,"en":"Do you monitor and enforce conformity with hardening baselines?","pt":"Vocês monitoram e impõem a conformidade com os baselines de hardening?","gen":["You perform conformity checks regularly, preferably using automation","You store conformity check results in an accessible location","You follow an established process to address reported non-conformities","You review each baseline at least annually, and update it when required"],"gpt":["Vocês fazem verificações de conformidade regularmente, de preferência automatizadas","Vocês armazenam os resultados em local acessível","Vocês seguem um processo estabelecido para tratar não-conformidades reportadas","Vocês revisam cada baseline ao menos anualmente e atualizam quando necessário"]},{"stream":"B","level":3,"en":"Do you regularly evaluate components and review patch level status?","pt":"Vocês avaliam regularmente os componentes e revisam o status do nível de patch?","gen":["You update the list with components and versions","You identify and update missing updates according to existing SLA","You review and update the process based on feedback from the people who perform patching"],"gpt":["Vocês atualizam a lista com componentes e versões","Vocês identificam e aplicam atualizações faltantes conforme o SLA existente","Vocês revisam e atualizam o processo com base no feedback de quem aplica os patches"]}]},{"name":"Operational Management","pt":"Gestão Operacional","code":"OM","A":{"en":"Data Protection","pt":"Proteção de Dados"},"B":{"en":"System Decommissioning / Legacy Management","pt":"Descomissionamento / Gestão de Legado"},"questions":[{"stream":"A","level":1,"en":"Do you protect and handle information according to protection requirements for data stored and processed on each application?","pt":"Vocês protegem e tratam as informações conforme os requisitos de proteção dos dados armazenados e processados em cada aplicação?","gen":["You know the data elements processed and stored by each application","You know the type and sensitivity level of each identified data element","You have controls to prevent propagation of unsanitized sensitive data from production to lower environments"],"gpt":["Vocês conhecem os elementos de dados processados e armazenados por cada aplicação","Vocês conhecem o tipo e o nível de sensibilidade de cada elemento de dados","Há controles para impedir a propagação de dados sensíveis não sanitizados de produção para ambientes inferiores"]},{"stream":"B","level":1,"en":"Do you identify and remove systems, applications, application dependencies, or services that are no longer used, have reached end of life, or are no longer actively developed or supported?","pt":"Vocês identificam e removem sistemas, aplicações, dependências ou serviços que não são mais usados, chegaram ao fim de vida ou não são mais ativamente desenvolvidos ou suportados?","gen":["You do not use unsupported applications or dependencies","You manage customer/user migration from older versions for each product and customer/user group"],"gpt":["Vocês não usam aplicações ou dependências sem suporte","Vocês gerenciam a migração de clientes/usuários de versões antigas para cada produto e grupo"]},{"stream":"A","level":2,"en":"Do you maintain a data catalog, including types, sensitivity levels, and processing and storage locations?","pt":"Vocês mantêm um catálogo de dados, incluindo tipos, níveis de sensibilidade e locais de processamento e armazenamento?","gen":["The data catalog is stored in an accessible location","You know which data elements are subject to specific regulation","You have controls for protecting and preserving data throughout its lifetime","You have retention requirements for data, and you destroy backups in a timely manner after the relevant retention period ends"],"gpt":["O catálogo de dados fica em local acessível","Vocês sabem quais elementos de dados estão sujeitos a regulação específica","Há controles para proteger e preservar os dados ao longo de sua vida","Há requisitos de retenção e vocês destroem backups no prazo após o término da retenção"]},{"stream":"B","level":2,"en":"Do you follow an established process for removing all associated resources, as part of decommissioning of unused systems, applications, application dependencies, or services?","pt":"Vocês seguem um processo estabelecido para remover todos os recursos associados ao descomissionar sistemas, aplicações, dependências ou serviços não utilizados?","gen":["You document the status of support for all released versions of your products, in an accessible location","The process includes replacement or upgrade of third-party applications, or application dependencies, that have reached end of life","Operating environments do not contain orphaned accounts, firewall rules, or other configuration artifacts"],"gpt":["Vocês documentam o status de suporte de todas as versões lançadas dos produtos, em local acessível","O processo inclui substituição ou upgrade de aplicações/dependências de terceiros que chegaram ao fim de vida","Os ambientes não contêm contas órfãs, regras de firewall ou artefatos de configuração obsoletos"]},{"stream":"A","level":3,"en":"Do you regularly review and update the data catalog and your data protection policies and procedures?","pt":"Vocês revisam e atualizam regularmente o catálogo de dados e suas políticas e procedimentos de proteção de dados?","gen":["You have automated monitoring to detect attempted or actual violations of the Data Protection Policy","You have tools for data loss prevention, access control and tracking, or anomalous behavior detection","You periodically audit the operation of automated mechanisms, including backups and record deletions"],"gpt":["Há monitoramento automatizado para detectar violações (tentadas ou reais) da Política de Proteção de Dados","Há ferramentas de DLP, controle/rastreamento de acesso ou detecção de comportamento anômalo","Vocês auditam periodicamente os mecanismos automatizados, incluindo backups e exclusões de registros"]},{"stream":"B","level":3,"en":"Do you regularly evaluate the lifecycle state and support status of every software asset and underlying infrastructure component, and estimate their end of life?","pt":"Vocês avaliam regularmente o estado do ciclo de vida e o status de suporte de cada ativo de software e componente de infraestrutura, estimando seu fim de vida?","gen":["Your end of life management process is agreed upon","You inform customers and user groups of product timelines to prevent disruption of service or support","You review the process at least annually"],"gpt":["Seu processo de gestão de fim de vida é acordado","Vocês informam clientes e grupos de usuários sobre os prazos do produto para evitar interrupção de serviço/suporte","Vocês revisam o processo ao menos anualmente"]}]}]}]};
